    45→/* ---- Base64 Encoding/Decoding Table --- */
    46→/* Padding character string starts at offset 64. */
    47→static const char base64encdec[]=
    48→  "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=";
