t should return an indication of success/error.\n\n\nSENDING COOKIE INFORMATION\n==========================\n\nstruct Cookies *Curl_cookie_getlist(struct CookieInfo *cookie,\n                                    char *host, char *path, bool secure);\n\n        For a given host and path, return a linked list of cookies that\n        the client should send to the server if used now. The secure\n        boolean informs the cookie if a secure connection is achieved or\n        not.\n\n        It shall only return cookies that haven't expired.\n\n\nExample set of cookies:\n\n    Set-cookie: PRODUCTINFO=webxpress; domain=.fidelity.com; path=/; secure\n    Set-cookie: PERSONALIZE=none;expires=Monday, 13-Jun-1988 03:04:55 GMT;\n    domain=.fidelity.com; path=/ftgw; secure\n    Set-cookie: FidHist=none;expires=Monday, 13-Jun-1988 03:04:55 GMT;\n    domain=.fidelity.com; path=/; secure\n    Set-cookie: FidOrder=none;expires=Monday, 13-Jun-1988 03:04:55 GMT;\n    domain=.fidelity.com; path=/; secure\n    Set-cookie: DisPend=none;expires=Monday, 13-Jun-1988 03:04:55 GMT;\n    domain=.fidelity.com; path=/; secure\n    Set-cookie: FidDis=none;expires=Monday, 13-Jun-1988 03:04:55 GMT;\n    domain=.fidelity.com; path=/; secure\n    Set-cookie:\n    Session_Key@6791a9e0-901a-11d0-a1c8-9b012c88aa77=none;expires=Monday,\n    13-Jun-1988 03:04:55 GMT; domain=.fidelity.com; path=/; secure\n****/\n\n\n#include \"curl_setup.h\"\n\n#if !defined(CURL_DISABLE_HTTP) && !defined(CURL_DISABLE_COOKIES)\n\n#include \"urldata.h\"\n#include \"cookie.h\"\n#include \"psl.h\"\n#include \"strtok.h\"\n#include \"sendf.h\"\n#include \"slist.h\"\n#include \"share.h\"\n#include \"strtoofft.h\"\n#include \"strcase.h\"\n#include \"curl_get_line.h\"\n#include \"curl_memrchr.h\"\n#include \"parsedate.h\"\n#include \"rename.h\"\n#include \"fopen.h\"\n#include \"strdup.h\"\n\n/* The last 3 #include files should be in this order */\n#include \"curl_printf.h\"\n#include \"curl_memory.h\"\n#include \"memdebug.h\"\n\nstatic void strstore(char **str, const char *newstr, size_t len);\n\nstatic void freecookie(struct Cookie *co)\n{\n  free(co->domain);\n  free(co->path);\n  free(co->spath);\n  free(co->name);\n  free(co->value);\n  free(co);\n}\n\nstatic bool cookie_tailmatch(const char *cookie_domain,\n                             size_t cookie_domain_len,\n                             const char *hostname)\n{\n  size_t hostname_len = strlen(hostname);\n\n  if(hostname_len < cookie_domain_len)\n    return FALSE;\n\n  if(!strncasecompare(cookie_domain,\n                      hostname + hostname_len-cookie_domain_len,\n                      cookie_domain_len))\n    return FALSE;\n\n  /*\n   * A lead char of cookie_domain is not '.'.\n   * RFC6265 4.1.2.3. The Domain Attribute says:\n   * For example, if the value of the Domain attribute is\n   * \"example.com\", the user agent will include the cookie in the Cookie\n   * header when making HTTP requests to example.com, www.example.com, and\n   * www.corp.example.com.\n   */\n  if(hostname_len == cookie_domain_len)\n    return TRUE;\n  if('.' == *(hostname + hostname_len - cookie_domain_len))\n    return TRUE;\n  return FALSE;\n}\n\n/*\n * matching cookie path and url path\n * RFC6265 5.1.4 Paths and Path-Match\n */\nstatic bool pathmatch(const char *cookie_path, const char *request_uri)\n{\n  size_t cookie_path_len;\n  size_t uri_path_len;\n  char *uri_path = NULL;\n  char *pos;\n  bool ret = FALSE;\n\n  /* cookie_path must not have last '/' separator. ex: /sample */\n  cookie_path_len = strlen(cookie_path);\n  if(1 == cookie_path_len) {\n    /* cookie_path must be '/' */\n    return TRUE;\n  }\n\n  uri_path = strdup(request_uri);\n  if(!uri_path)\n    return FALSE;\n  pos = strchr(uri_path, '?');\n  if(pos)\n    *pos = 0x0;\n\n  /* #-fragments are already cut off! */\n  if(0 == strlen(uri_path) || uri_path[0] != '/') {\n    strstore(&uri_path, \"/\", 1);\n    if(!uri_path)\n      return FALSE;\n  }\n\n  /*\n   * here, RFC6265 5.1.4 says\n   *  4. Output the characters of the uri-path from the first character up\n   *     to, but not including, the right-most %x2F (\"/\").\n   *  but URL path /hoge?fuga=xxx means /hoge/index.cgi?fuga=xxx in some site\n   *  without redirect.\n   *  Ignore this algorithm because /hoge is uri path for this case\n   *  (uri path is not /).\n   */\n\n  uri_path_len = strlen(uri_path);\n\n  if(uri_path_len < cookie_path_len) {\n    ret = FALSE;\n    goto pathmatched;\n  }\n\n  /* not using checkprefix() because matching should be case-sensitive */\n  if(strncmp(cookie_path, uri_path, cookie_path_len)) {\n    ret = FALSE;\n    goto pathmatched;\n  }\n\n  /* The cookie-path and the uri-path are identical. */\n  if(cookie_path_len == uri_path_len) {\n    ret = TRUE;\n    goto pathmatched;\n  }\n\n  /* here, cookie_path_len < uri_path_len */\n  if(uri_path[cookie_path_len] == '/') {\n    ret = TRUE;\n    goto pathmatched;\n  }\n\n  ret = FALSE;\n\npathmatched:\n  free(uri_path);\n  return ret;\n}\n\n/*\n * Return the top-level domain, for optimal hashing.\n */\nstatic const char *get_top_domain(const char * const domain, size_t *outlen)\n{\n  size_t len = 0;\n  const char *first = NULL, *last;\n\n  if(domain) {\n    len = strlen(domain);\n    last = memrchr(domain, '.', len);\n    if(last) {\n      first = memrchr(domain, '.', (last - domain));\n      if(first)\n        len -= (++first - domain);\n    }\n  }\n\n  if(outlen)\n    *outlen = len;\n\n  return first? first: domain;\n}\n\n/* Avoid C1001, an \"internal error\" with MSVC14 */\n#if defined(_MSC_VER) && (_MSC_VER == 1900)\n#pragma optimize(\"\", off)\n#endif\n\n/*\n * A case-insensitive hash for the cookie domains.\n */\nstatic size_t cookie_hash_domain(const char *domain, const size_t len)\n{\n  const char *end = domain + len;\n  size_t h = 5381;\n\n  while(domain < end) {\n    h += h << 5;\n    h ^= Curl_raw_toupper(*domain++);\n  }\n\n  return (h % COOKIE_HASH_SIZE);\n}\n\n#if defined(_MSC_VER) && (_MSC_VER == 1900)\n#pragma optimize(\"\", on)\n#endif\n\n/*\n * Hash this domain.\n */\nstatic size_t cookiehash(const char * const domain)\n{\n  const char *top;\n  size_t len;\n\n  if(!domain || Curl_host_is_ipnum(domain))\n    return 0;\n\n  top = get_top_domain(domain, &len);\n  return cookie_hash_domain(top, len);\n}\n\n/*\n * cookie path sanitize\n */\nstatic char *sanitize_cookie_path(const char *cookie_path)\n{\n  size_t len;\n  char *new_path = strdup(cookie_path);\n  if(!new_path)\n    return NULL;\n\n  /* some stupid site sends path attribute with '\"'. */\n  len = strlen(new_path);\n  if(new_path[0] == '\\\"') {\n    memmove(new_path, new_path + 1, len);\n    len--;\n  }\n  if(len && (new_path[len - 1] == '\\\"')) {\n    new_path[--len] = 0x0;\n  }\n\n  /* RFC6265 5.2.4 The Path Attribute */\n  if(new_path[0] != '/') {\n    /* Let cookie-path be the default-path. */\n    strstore(&new_path, \"/\", 1);\n    return new_path;\n  }\n\n  /* convert /hoge/ to /hoge */\n  if(len && new_path[len - 1] == '/') {\n    new_path[len - 1] = 0x0;\n  }\n\n  return new_path;\n}\n\n/*\n * Load cookies from all given cookie files (CURLOPT_COOKIEFILE).\n *\n * NOTE: OOM or cookie parsing failures are ignored.\n */\nvoid Curl_cookie_loadfiles(struct Curl_easy *data)\n{\n  struct curl_slist *list = data->set.cookielist;\n  if(list) {\n    Curl_share_lock(data, CURL_LOCK_DATA_COOKIE, CURL_LOCK_ACCESS_SINGLE);\n    while(list) {\n      struct CookieInfo *newcookies =\n        Curl_cookie_init(data, list->data, data->cookies,\n                         data->set.cookiesession);\n      if(!newcookies)\n        /*\n         * Failure may be due to OOM or a bad cookie; both are ignored\n         * but only the first should be\n         */\n        infof(data, \"ignoring failed cookie_init for %s\", list->data);\n      else\n        data->cookies = newcookies;\n      list = list->next;\n    }\n    Curl_share_unlock(data, CURL_LOCK_DATA_COOKIE);\n  }\n}\n\n/*\n * strstore\n *\n * A thin wrapper around strdup which ensures that any memory allocated at\n * *str will be freed before the string allocated by strdup is stored there.\n * The intended usecase is repeated assignments to the same variable during\n * parsing in a last-wins scenario. The caller is responsible for checking\n * for OOM errors.\n */\nstatic void strstore(char **str, const char *newstr, size_t len)\n{\n  DEBUGASSERT(newstr);\n  DEBUGASSERT(str);\n  free(*str);\n  *str = Curl_memdup(newstr, len + 1);\n  if(*str)\n    (*str)[len] = 0;\n}\n\n/*\n * remove_expired\n *\n * Remove expired cookies from the hash by inspecting the expires timestamp on\n * each cookie in the hash, freeing and deleting any where the timestamp is in\n * the past.  If the cookiejar has recorded the next timestamp at which one or\n * more cookies expire, then processing will exit early in case this timestamp\n * is in the future.\n */\nstatic void remove_expired(struct CookieInfo *cookies)\n{\n  struct Cookie *co, *nx;\n  curl_off_t now = (curl_off_t)time(NULL);\n  unsigned int i;\n\n  /*\n   * If the earliest expiration timestamp in the jar is in the future we can\n   * skip scanning the whole jar and instead exit early as there won't be any\n   * cookies to evict.  If we need to evict however, reset the next_expiration\n   * counter in order to track the next one. In case the recorded first\n   * expiration is the max offset, then perform the safe fallback of checking\n   * all cookies.\n   */\n  if(now < cookies->next_expiration &&\n      cookies->next_expiration != CURL_OFF_T_MAX)\n    return;\n  else\n    cookies->next_expiration = CURL_OFF_T_MAX;\n\n  for(i = 0; i < COOKIE_HASH_SIZE; i++) {\n    struct Cookie *pv = NULL;\n    co = cookies->cookies[i];\n    while(co) {\n      nx = co->next;\n      if(co->expires && co->expires < now) {\n        if(!pv) {\n          cookies->cookies[i] = co->next;\n        }\n        else {\n          pv->next = co->next;\n        }\n        cookies->numcookies--;\n        freecookie(co);\n      }\n      else {\n        /*\n         * If this cookie has an expiration timestamp earlier than what we've\n         * seen so far then record it for the next round of expirations.\n         */\n        if(co->expires && co->expires < cookies->next_expiration)\n          cookies->next_expiration = co->expires;\n        pv = co;\n      }\n      co = nx;\n    }\n  }\n}\n\n/* Make sure domain contains a dot or is localhost. */\nstatic bool bad_domain(const char *domain, size_t len)\n{\n  if((len == 9) && strncasecompare(domain, \"localhost\", 9))\n    return FALSE;\n  else {\n    /* there must be a dot present, but that dot must not be a trailing dot */\n    char *dot = memchr(domain, '.', len);\n    if(dot) {\n      size_t i = dot - domain;\n      if((len - i) > 1)\n        /* the dot is not the last byte */\n        return FALSE;\n    }\n  }\n  return TRUE;\n}\n\n/*\n  RFC 6265 section 4.1.1 says a server should accept this range:\n\n  cookie-octet    = %x21 / %x23-2B / %x2D-3A / %x3C-5B / %x5D-7E\n\n  But Firefox and Chrome as of June 2022 accept space, comma and double-quotes\n  fine. The prime reason for filtering out control bytes is that some HTTP\n  servers return 400 for requests that contain such.\n*/\nstatic int invalid_octets(const char *p)\n{\n  /* Reject all bytes \\x01 - \\x1f (*except* \\x09, TAB) + \\x7f */\n  static const char badoctets[] = {\n    \"\\x01\\x02\\x03\\x04\\x05\\x06\\x07\\x08\\x0a\"\n    \"\\x0b\\x0c\\x0d\\x0e\\x0f\\x10\\x11\\x12\\x13\\x14\"\n    \"\\x15\\x16\\x17\\x18\\x19\\x1a\\x1b\\x1c\\x1d\\x1e\\x1f\\x7f\"\n  };\n  size_t len;\n  /* scan for all the octets that are *not* in cookie-octet */\n  len = strcspn(p, badoctets);\n  return (p[len] != '\\0');\n}\n\n/*\n * Curl_cookie_add\n *\n * Add a single cookie line to the cookie keeping object. Be aware that\n * sometimes we get an IP-only host name, and that might also be a numerical\n * IPv6 address.\n *\n * Returns NULL on out of memory or invalid cookie. This is suboptimal,\n * as they should be treated separately.\n */\nstruct Cookie *\nCurl_cookie_add(struct Curl_easy *data,\n                struct CookieInfo *c,\n                bool httpheader, /* TRUE if HTTP header-style line */\n                bool noexpire, /* if TRUE, skip remove_expired() */\n                const char *lineptr,   /* first character of the line */\n                const char *domain, /* default domain */\n                const char *path,   /* full path used when this cookie is set,\n                                       used to get default path for the cookie\n                                       unless set */\n                bool secure)  /* TRUE if connection is over secure origin */\n{\n  struct Cookie *clist;\n  struct Cookie *co;\n  struct Cookie *lastc = NULL;\n  struct Cookie *replace_co = NULL;\n  struct Cookie *replace_clist = NULL;\n  time_t now = time(NULL);\n  bool replace_old = FALSE;", "numLines": 500, "startLine": 1, "totalLines": 1780}}

